// ── Search index ──────────────────────────────────────────
const _FOOD_IDX = {};
FOOD_DB.forEach(f => { _FOOD_IDX[f.id] = f; });

function searchFoods(q) {
  if (!q) return [];
  const terms = q.toLowerCase().trim().split(/\s+/);
  const scored = [];
  for (const f of FOOD_DB) {
    const haystack = (f.name + ' ' + (f.aliases || []).join(' ')).toLowerCase();
    let score = 0; let allMatch = true;
    for (const t of terms) {
      if (haystack.includes(t)) {
        if (f.name.toLowerCase().startsWith(t)) score += 3;
        else if (f.name.toLowerCase().includes(t)) score += 2;
        else score += 1;
      } else { allMatch = false; break; }
    }
    if (allMatch && score > 0) scored.push({ f, score });
  }
  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, 40).map(x => x.f);
}
// Total: 10500 foods